def evaluate_expression(expression):
 if isinstance(expression, int):
 return expression
 elif isinstance(expression, tuple):
 left_value = evaluate_expression(expression[0])
 right_value = evaluate_expression(expression[2])
 operator = expression[1]
 if operator == '+':
 return left_value + right_value
 elif operator == '*':
 return left_value * right_value

#include <stdio.h>

int evaluate_expression(int left, char operator, int right) {
 switch (operator) {
 case '+':
 return left + right;
 case '*':
 return left * right;
 }
}

int main() {
 int result = evaluate_expression(2, '+', 3);
 printf("Result: %d\n", result);
 return 0;
}
